// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx (vẫn dùng để đọc CSV)
import './KhaiBaoCoSo.css'; // Import file CSS
import speciesOptions from '../data/speciesData'; // Import danh sách loài từ file mới (nếu có)
import { jwtDecode } from 'jwt-decode'; // Import jwtDecode để giải mã token
import { useNavigate } from 'react-router-dom'; // Import useNavigate

function KhaiBaoCoSo() {
  const navigate = useNavigate(); // Khởi tạo hook useNavigate

  // Initial form state for resetting
  const initialFormState = {
    // Thông tin cơ sở
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    
    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    
    // Cơ sở gây nuôi
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    
    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
    loaiHinhCheBienGo: '', // <-- TRƯỜNG MỚI ĐÃ THÊM
    nguonGocGo: '',       // <-- TRƯỜNG MỚI ĐÃ THÊM
    
    // Loại cơ sở đăng ký (dropdown)
    loaiCoSoDangKy: '', // Thêm trường này
    
    // Lâm sản (nếu là cơ sở kinh doanh, chế biến gỗ)
    tenLamSan: '',
    tenKhoaHoc: '',
    
    // Giấy phép
    issueDate: '',
    expiryDate: '',

    // Trạng thái
    trangThai: 'Đang hoạt động', // Mặc định là 'Đang hoạt động'
  };

  const [formData, setFormData] = useState(initialFormState);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [csvFile, setCsvFile] = useState(null); // State để lưu trữ file CSV đã chọn
  const [excelData, setExcelData] = useState([]); // State để lưu trữ dữ liệu từ file Excel/CSV
  const [isLoading, setIsLoading] = useState(false); // State cho trạng thái tải lên hàng loạt
  const [isAdmin, setIsAdmin] = useState(false); // State để kiểm tra quyền admin
  const [message, setMessage] = useState({ type: '', text: '' }); // State cho thông báo chung

  // useEffect để kiểm tra quyền admin khi component mount
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        const decodedToken = jwtDecode(token);
        if (decodedToken.role === 'admin') {
          setIsAdmin(true);
        }
      } catch (err) {
        console.error('Lỗi giải mã token:', err);
        // Xử lý lỗi giải mã token, ví dụ: xóa token và chuyển hướng về trang đăng nhập
        localStorage.removeItem('token');
        navigate('/login');
      }
    } else {
      // Nếu không có token, chuyển hướng về trang đăng nhập
      navigate('/login');
    }
  }, [navigate]);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData(prevData => ({
      ...prevData,
      [name]: value
    }));
  }, []);

  const resetForm = useCallback(() => {
    setFormData(initialFormState);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' }); // Reset thông báo
  }, [initialFormState]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' }); // Reset thông báo

    const token = localStorage.getItem('token');
    if (!token) {
      setMessage({ type: 'error', text: 'Bạn chưa đăng nhập. Vui lòng đăng nhập lại.' });
      setLoading(false);
      navigate('/login');
      return;
    }

    try {
      const response = await axios.post('http://localhost:10000/api/farms', formData, {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });
      setSuccessMessage('Đăng ký cơ sở thành công!');
      setMessage({ type: 'success', text: 'Đăng ký cơ sở thành công!' });
      resetForm();
      console.log('Cơ sở đã đăng ký:', response.data);
    } catch (err) {
      console.error('Lỗi khi đăng ký cơ sở:', err.response?.data || err.message);
      if (err.response && err.response.status === 409) {
        // Xử lý lỗi trùng lặp từ backend
        const farmId = err.response.data.farmId;
        setMessage({ 
          type: 'error', 
          text: `Cơ sở này đã tồn tại trong hệ thống. ID của cơ sở trùng lặp: ${farmId || 'Không rõ ID'}.` 
        });
      } else if (err.response && err.response.data && err.response.data.message) {
        setError(err.response.data.message);
        setMessage({ type: 'error', text: err.response.data.message });
      } else {
        setError('Đăng ký cơ sở thất bại. Vui lòng thử lại.');
        setMessage({ type: 'error', text: 'Đăng ký cơ sở thất bại. Vui lòng thử lại.' });
      }
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setCsvFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        const data = new Uint8Array(event.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = XLSX.utils.sheet_to_json(worksheet, { header: 1 }); // Đọc với header là 1 để lấy mảng các mảng

        // Giả định hàng đầu tiên là header
        const headers = json[0];
        const rows = json.slice(1);

        // Ánh xạ tên cột tiếng Việt sang tên trường tiếng Anh trong schema
        const columnMapping = {
          'Tên cơ sở': 'tenCoSo',
          'Tỉnh (TP)': 'tinhThanhPho',
          'Xã (Phường)': 'xaPhuong',
          'Địa chỉ cơ sở': 'diaChiCoSo',
          'Vĩ độ': 'vido',
          'Kinh độ': 'kinhdo',
          'Loại hình cơ sở': 'loaiHinhCoSo',
          'Ngày thành lập': 'ngayThanhLap',
          'Giấy phép kinh doanh': 'giayPhepKinhDoanh',
          'Tên người đại diện': 'tenNguoiDaiDien',
          'Năm sinh': 'namSinh',
          'Số CCCD/Hộ chiếu': 'soCCCD',
          'Ngày cấp CCCD': 'ngayCapCCCD',
          'Nơi cấp CCCD': 'noiCapCCCD',
          'Số điện thoại người đại diện': 'soDienThoaiNguoiDaiDien',
          'Địa chỉ người đại diện': 'diaChiNguoiDaiDien',
          'Email người đại diện': 'emailNguoiDaiDien',
          'Mục đích nuôi': 'mucDichNuoi',
          'Hình thức nuôi': 'hinhThucNuoi',
          'Mã số cơ sở gây nuôi': 'maSoCoSoGayNuoi',
          'Tổng đàn': 'tongDan',
          'Loại hình kinh doanh gỗ': 'loaiHinhKinhDoanhGo',
          'Ngành nghề kinh doanh gỗ': 'nganhNgheKinhDoanhGo',
          'Khối lượng': 'khoiLuong',
          'Loại cơ sở đăng ký': 'loaiCoSoDangKy',
          'Tên lâm sản': 'tenLamSan',
          'Tên khoa học': 'tenKhoaHoc',
          'Ngày cấp phép': 'issueDate',
          'Ngày hết hạn': 'expiryDate',
          'Trạng thái': 'trangThai',
          'Ghi chú': 'ghiChu',
          'Loại hình chế biến gỗ': 'loaiHinhCheBienGo', // <-- MAPPING MỚI
          'Nguồn gốc gỗ': 'nguonGocGo'             // <-- MAPPING MỚI
        };

        const parsedData = rows.map(row => {
          const rowObject = {};
          headers.forEach((header, index) => {
            const englishKey = columnMapping[header.trim()];
            if (englishKey) {
              let value = row[index];
              // Chuyển đổi ngày từ định dạng số Excel sang Date object hoặc string ISO
              if (['ngayThanhLap', 'ngayCapCCCD', 'issueDate', 'expiryDate'].includes(englishKey) && typeof value === 'number') {
                // XLSX.SSF.parse_date_code trả về một đối tượng với các thuộc tính như year, month, day
                const date = XLSX.SSF.parse_date_code(value);
                // Tạo đối tượng Date (tháng trong JS là 0-11)
                const jsDate = new Date(date.y, date.m - 1, date.d);
                value = jsDate.toISOString().split('T')[0]; // Định dạng YYYY-MM-DD
              }
              rowObject[englishKey] = value;
            }
          });
          // Đảm bảo các trường số được chuyển đổi đúng kiểu
          if (rowObject.vido) rowObject.vido = parseFloat(rowObject.vido);
          if (rowObject.kinhdo) rowObject.kinhdo = parseFloat(rowObject.kinhdo);
          if (rowObject.namSinh) rowObject.namSinh = parseInt(rowObject.namSinh, 10);
          if (rowObject.tongDan) rowObject.tongDan = parseInt(rowObject.tongDan, 10);
          if (rowObject.khoiLuong) rowObject.khoiLuong = parseFloat(rowObject.khoiLuong);
          return rowObject;
        });
        setExcelData(parsedData);
        setMessage({ type: 'info', text: `Đã đọc được ${parsedData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.` });
        setError(null); // Clear previous errors
        setSuccessMessage(null); // Clear previous success messages
      };
      reader.readAsArrayBuffer(file);
    } else {
      setCsvFile(null);
      setExcelData([]);
      setMessage({ type: '', text: '' });
    }
  };

  const handleBulkSubmit = async () => {
    setIsLoading(true);
    setMessage({ type: '', text: '' }); // Reset thông báo
    const token = localStorage.getItem('token');
    if (!token) {
      setMessage({ type: 'error', text: 'Bạn chưa đăng nhập. Vui lòng đăng nhập lại.' });
      setIsLoading(false);
      navigate('/login');
      return;
    }

    try {
      const response = await axios.post('http://localhost:10000/api/farms/bulk', excelData, {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });
      // Xử lý phản hồi thành công từ backend (nếu có)
      setMessage({ type: 'success', text: `Tải lên hàng loạt thành công! Đã lưu ${response.data.savedFarms.length} cơ sở.` });
      setExcelData([]); // Clear data after successful upload
      setCsvFile(null); // Clear file after successful upload
      console.log('Bulk upload response:', response.data);
    } catch (err) {
      console.error('Lỗi khi tải lên hàng loạt:', err.response?.data || err.message);
      if (err.response && err.response.data && err.response.data.errors) {
        const bulkErrors = err.response.data.errors;
        let errorMessage = `Có lỗi xảy ra khi tải lên hàng loạt. Đã lưu ${err.response.data.savedCount || 0} cơ sở.`;
        
        const duplicateErrors = bulkErrors.filter(e => e.type === 'duplicate');
        const validationErrors = bulkErrors.filter(e => e.type !== 'duplicate');

        if (duplicateErrors.length > 0) {
          errorMessage += ` ${duplicateErrors.length} cơ sở bị trùng lặp: `;
          duplicateErrors.forEach((dupErr, index) => {
            errorMessage += `[Dòng ${dupErr.index + 2}: ID ${dupErr.farmId || 'Không rõ ID'}]`; // +2 vì hàng 0 là header, hàng 1 là dòng đầu tiên của data
            if (index < duplicateErrors.length - 1) errorMessage += '; ';
          });
        }
        if (validationErrors.length > 0) {
          errorMessage += ` ${validationErrors.length} cơ sở có lỗi dữ liệu khác.`;
        }
        setMessage({ type: 'error', text: errorMessage });
      } else if (err.response && err.response.data && err.response.data.message) {
        setMessage({ type: 'error', text: err.response.data.message });
      } else {
        setMessage({ type: 'error', text: 'Tải lên hàng loạt thất bại. Vui lòng kiểm tra file và thử lại.' });
      }
    } finally {
      setIsLoading(false);
    }
  };

  const resetCsvUpload = () => {
    setCsvFile(null);
    setExcelData([]);
    setMessage({ type: '', text: '' });
  };

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở</h2>

      {message.type && (
        <div className={`message ${message.type}`}>
          {message.text}
          <button onClick={() => setMessage({ type: '', text: '' })} className="close-message-button">x</button>
        </div>
      )}

      <form onSubmit={handleSubmit} className="khai-bao-form">
        {/* Thông tin cơ sở */}
        <section className="khai-bao-section">
          <h3>Thông tin cơ sở</h3>
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở:</label>
            <input type="text" id="tenCoSo" name="tenCoSo" value={formData.tenCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
            <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={formData.tinhThanhPho} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="xaPhuong">Xã (Phường):</label>
            <input type="text" id="xaPhuong" name="xaPhuong" value={formData.xaPhuong} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở:</label>
            <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={formData.diaChiCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="vido">Vĩ độ:</label>
            <input type="number" id="vido" name="vido" value={formData.vido} onChange={handleChange} step="any" />
          </div>
          <div className="form-group">
            <label htmlFor="kinhdo">Kinh độ:</label>
            <input type="number" id="kinhdo" name="kinhdo" value={formData.kinhdo} onChange={handleChange} step="any" />
          </div>
          <div className="form-group">
            <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
            <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={formData.ngayThanhLap} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="giayPhepKinhDoanh">Số giấy phép kinh doanh:</label>
            <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={formData.giayPhepKinhDoanh} onChange={handleChange} />
          </div>
        </section>

        {/* Thông tin người đại diện */}
        <section className="khai-bao-section">
          <h3>Thông tin người đại diện</h3>
          <div className="form-group">
            <label htmlFor="tenNguoiDaiDien">Tên người đại diện:</label>
            <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={formData.tenNguoiDaiDien} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="namSinh">Năm sinh:</label>
            <input type="number" id="namSinh" name="namSinh" value={formData.namSinh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soCCCD">Số CCCD/Hộ chiếu:</label>
            <input type="text" id="soCCCD" name="soCCCD" value={formData.soCCCD} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="ngayCapCCCD">Ngày cấp CCCD:</label>
            <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={formData.ngayCapCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="noiCapCCCD">Nơi cấp CCCD:</label>
            <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={formData.noiCapCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại người đại diện:</label>
            <input type="tel" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={formData.soDienThoaiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiNguoiDaiDien">Địa chỉ người đại diện:</label>
            <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={formData.diaChiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="emailNguoiDaiDien">Email người đại diện:</label>
            <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={formData.emailNguoiDaiDien} onChange={handleChange} />
          </div>
        </section>

        {/* Loại cơ sở đăng ký */}
        <section className="khai-bao-section">
          <h3>Loại cơ sở đăng ký</h3>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở đăng ký:</label>
            <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>
        </section>

        {/* Conditional fields based on loaiCoSoDangKy */}
        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Thông tin cơ sở gây nuôi</h3>
            <div className="form-group">
              <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
              <input type="text" id="mucDichNuoi" name="mucDichNuoi" value={formData.mucDichNuoi} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
              <input type="text" id="hinhThucNuoi" name="hinhThucNuoi" value={formData.hinhThucNuoi} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở gây nuôi:</label>
              <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={formData.maSoCoSoGayNuoi} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="tongDan">Tổng đàn (con):</label>
              <input type="number" id="tongDan" name="tongDan" value={formData.tongDan} onChange={handleChange} />
            </div>
            {/* Thêm trường chọn loài */}
            <div className="form-group">
              <label htmlFor="tenLamSan">Loài nuôi:</label>
              <select id="tenLamSan" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange}>
                <option value="">-- Chọn loài --</option>
                {speciesOptions.map((species, index) => (
                  <option key={index} value={species.name}>{species.name}</option>
                ))}
              </select>
            </div>
            <div className="form-group">
                <label htmlFor="tenKhoaHoc">Tên khoa học (tự động điền):</label>
                <input 
                    type="text" 
                    id="tenKhoaHoc" 
                    name="tenKhoaHoc" 
                    value={speciesOptions.find(s => s.name === formData.tenLamSan)?.scientificName || ''} 
                    readOnly 
                    disabled // Không cho phép chỉnh sửa
                />
            </div>
          </section>
        )}

        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
          <section className="khai-bao-section">
            <h3>Thông tin cơ sở kinh doanh, chế biến gỗ</h3>
            <div className="form-group">
              <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
              <input type="text" id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={formData.loaiHinhKinhDoanhGo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề kinh doanh gỗ:</label>
              <input type="text" id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={formData.nganhNgheKinhDoanhGo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="khoiLuong">Khối lượng (m³):</label>
              <input type="number" id="khoiLuong" name="khoiLuong" value={formData.khoiLuong} onChange={handleChange} step="any" />
            </div>
            
            {/* ====== CÁC TRƯỜNG MỚI ĐƯỢC THÊM TẠI ĐÂY ====== */}
            <div className="form-group">
              <label htmlFor="loaiHinhCheBienGo">Loại hình chế biến gỗ:</label>
              <select id="loaiHinhCheBienGo" name="loaiHinhCheBienGo" value={formData.loaiHinhCheBienGo} onChange={handleChange}>
                <option value="">-- Chọn loại hình --</option>
                <option value="Tròn">Tròn</option>
                <option value="Xẻ">Xẻ</option>
                <option value="Thành phẩm">Thành phẩm</option>
              </select>
            </div>
            <div className="form-group">
              <label htmlFor="nguonGocGo">Nguồn gốc gỗ:</label>
              <select id="nguonGocGo" name="nguonGocGo" value={formData.nguonGocGo} onChange={handleChange}>
                <option value="">-- Chọn nguồn gốc --</option>
                <option value="Nhập khẩu">Nhập khẩu</option>
                <option value="Vườn">Vườn</option>
                <option value="Khác">Khác</option>
              </select>
            </div>
            {/* ====== KẾT THÚC PHẦN THÊM MỚI ====== */}

            <div className="form-group">
              <label htmlFor="tenLamSan">Tên lâm sản:</label>
              <input type="text" id="tenLamSan" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
              <input type="text" id="tenKhoaHoc" name="tenKhoaHoc" value={formData.tenKhoaHoc} onChange={handleChange} />
            </div>
          </section>
        )}

        {/* Thông tin giấy phép và trạng thái */}
        <section className="khai-bao-section">
          <h3>Thông tin giấy phép và trạng thái</h3>
          <div className="form-group">
            <label htmlFor="issueDate">Ngày cấp phép:</label>
            <input type="date" id="issueDate" name="issueDate" value={formData.issueDate} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="expiryDate">Ngày hết hạn:</label>
            <input type="date" id="expiryDate" name="expiryDate" value={formData.expiryDate} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="trangThai">Trạng thái:</label>
            <select id="trangThai" name="trangThai" value={formData.trangThai} onChange={handleChange}>
              <option value="Đang hoạt động">Đang hoạt động</option>
              <option value="Đã đóng cửa">Đã đóng cửa</option>
              <option value="Tạm dừng">Tạm ngưng</option>
            </select>
          </div>
          <div className="form-group">
            <label htmlFor="ghiChu">Ghi chú:</label>
            <textarea id="ghiChu" name="ghiChu" value={formData.ghiChu} onChange={handleChange} rows="3"></textarea>
          </div>
        </section>

        <div className="form-actions">
          <button type="submit" className="submit-button" disabled={loading}>
            {loading ? 'Đang gửi...' : 'Đăng ký cơ sở'}
          </button>
          <button type="button" onClick={resetForm} className="reset-button" disabled={loading}>
            Đặt lại biểu mẫu
          </button>
        </div>
      </form>

      {isAdmin && <hr className="section-divider" />}

      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <h3>Tải lên hàng loạt từ file CSV</h3>
          <div className="file-upload-group">
            <label htmlFor="csvUpload" className="file-upload-label">
              Chọn file CSV (.csv):
            </label>
            <input 
              type="file" 
              id="csvUpload" 
              accept=".csv" 
              onChange={handleFileUpload} 
              className="file-input"
            />
            {csvFile && <span className="file-name">{csvFile.name}</span>}
          </div>
          {excelData.length > 0 && (
            <div className="excel-preview-info">
              <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
              <button 
                onClick={handleBulkSubmit} 
                className="submit-button bulk-upload-button"
                disabled={isLoading}
              >
                {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
              </button>
              <button 
                onClick={resetCsvUpload} 
                className="clear-excel-button"
                disabled={isLoading}
              >
                Xóa dữ liệu CSV
              </button>
            </div>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
